// ── أنواع البيانات ────────────────────────────────────────────────
export type RelationType  = 'DIRECT' | 'INDIRECT' | 'OPERATIONAL' | 'SENTIMENT'
export type MarketState   = 'RISK_ON' | 'NEUTRAL' | 'RISK_OFF'
export type NewsDirection = 'POSITIVE' | 'NEGATIVE' | 'NEUTRAL'
 
export interface OwnershipRelation {
  id:            number
  owner_code:    string
  owner_name:    string
  owned_code:    string
  owned_name:    string
  ownership_pct: number
  relation_type: RelationType
  layer:         1 | 2 | 3 | 4
  strength:      number
  decay_factor:  number
  owner_sector:  string
  owned_sector:  string
  source:        string
  verified:      boolean
}
 
export interface NewsType {
  type_id:        string
  name_ar:        string
  direction:      NewsDirection
  lambda:         number
  half_life_hrs:  number
  default_s:      number
  sector_impacts: Record<string, number>
}
 
export interface StockNetwork {
  code:             string
  name_ar:          string
  sector:           string
  market:           'TASI' | 'NOMU'
  network_score:    number
  is_owner:         boolean
  is_owned:         boolean
  liquidity_factor: number
}
 
